from elasticsearch import Elasticsearch
from elasticsearch.helpers import scan
import json

class DynamicAggregationClient:
    def __init__(self, hosts=['localhost:9200']):
        self.es = Elasticsearch(hosts=hosts)
    
    def execute_script_aggregation(self, index, script_code, aggregation_type='terms', field=None, size=10):
        if not self.es.ping():
            raise Exception("Cannot connect to Elasticsearch")
        
        script = {
            "script": {
                "source": script_code
            }
        }
        
        if aggregation_type == 'terms':
            aggs = {
                "aggregation_result": {
                    "terms": {
                        "script": script,
                        "size": size
                    }
                }
            }
        elif aggregation_type == 'avg':
            aggs = {
                "aggregation_result": {
                    "avg": {
                        "script": script
                    }
                }
            }
        elif aggregation_type == 'sum':
            aggs = {
                "aggregation_result": {
                    "sum": {
                        "script": script
                    }
                }
            }
        else:
            raise ValueError("Unsupported aggregation type")
        
        query = {
            "aggs": aggs,
            "size": 0
        }
        
        try:
            response = self.es.search(index=index, body=query)
            return response['aggregations']['aggregation_result']['buckets'] if aggregation_type == 'terms' else response['aggregations']['aggregation_result']
        except Exception as e:
            raise Exception(f"Aggregation execution failed: {str(e)}")
    
    def execute_dynamic_script(self, index, script_code, params=None):
        if not self.es.ping():
            raise Exception("Cannot connect to Elasticsearch")
        
        query = {
            "script": {
                "source": script_code
            }
        }
        
        if params:
            query["script"]["params"] = params
        
        try:
            response = self.es.search(index=index, body=query)
            return response
        except Exception as e:
            raise Exception(f"Script execution failed: {str(e)}")

